// gen-pack-bundle.mjs — the handoff pack → one downloadable bundle (epic #1, ticket #14).
// Reads every file under handoff/verdant/ (recursively, sorted, deterministically), excluding
// the bundle artifact itself, and inlines each as a UTF-8 string into one pack.bundle.json.
// Every pack file is UTF-8 text (json/css/md/swift/xml/mjs — no binaries), so this is lossless
// AND the bundle is itself human-readable + git-diffable (matching the repo's inspectable-proof
// principle). Zero-dep — no zlib/CRC. Determinism is mandatory: the #9 drift gate re-runs this
// and git-porcelains handoff/, so the file order and byte output must be stable.
// Standalone:  node agent-layer/gen-pack-bundle.mjs
// Paths resolve from this module (NOT cwd) — build.mjs runs from the jobs folder.

import { readdirSync, readFileSync, writeFileSync } from "node:fs";
import { dirname, join, relative, resolve, sep } from "node:path";
import { fileURLToPath, pathToFileURL } from "node:url";

const ROOT = resolve(dirname(fileURLToPath(import.meta.url)), "..");
const PACK_DIR = join(ROOT, "handoff/verdant");
const BUNDLE_NAME = "pack.bundle.json";

// Recurse into `dir`, collecting absolute file paths. Hidden entries (dotfiles like a
// stray .DS_Store) are skipped — no pack file is hidden, and inlining one via
// readFileSync(..,"utf8") would mangle its binary bytes, breaking the bundle's
// lossless-UTF-8 + determinism guarantee.
function walk(dir, acc = []) {
  for (const ent of readdirSync(dir, { withFileTypes: true })) {
    if (ent.name.startsWith(".")) continue; // skip .DS_Store & other hidden junk
    const full = join(dir, ent.name);
    if (ent.isDirectory()) walk(full, acc);
    else acc.push(full);
  }
  return acc;
}

export function genPackBundle() {
  const bundlePath = join(PACK_DIR, BUNDLE_NAME);
  // Collect the whole tree, THEN sort the POSIX-normalized relative paths — readdir order is
  // not stable across OSes, so sorting the flat list (not inserting during the walk) is what
  // makes the files-map insertion order, and thus the bytes, deterministic.
  const keys = walk(PACK_DIR)
    .map((p) => relative(PACK_DIR, p).split(sep).join("/")) // stable cross-OS keys
    .filter((rel) => rel !== BUNDLE_NAME) // never inline the bundle into itself
    .sort();

  const files = {};
  for (const rel of keys) files[rel] = readFileSync(join(PACK_DIR, rel.split("/").join(sep)), "utf8");

  const bundle = {
    $description:
      "Verdant handoff pack, bundled — every file under handoff/verdant/ inlined as a UTF-8 string. Generated by agent-layer/gen-pack-bundle.mjs — do not edit. Unpack: for (const [p, c] of Object.entries(bundle.files)) { mkdirSync(dirname(p), { recursive: true }); writeFileSync(p, c); } — mkdirSync is required because 12 of the keys are nested (contracts/, tokens/, wc/) and writeFileSync does not create parent dirs.",
    scenario: "verdant",
    generatedFrom: "handoff/verdant",
    files,
  };
  const out = JSON.stringify(bundle, null, 2) + "\n";
  writeFileSync(bundlePath, out);
  return { files: keys.length, bytes: out.length, dest: bundlePath };
}

// pathToFileURL, not `file://${argv[1]}`: this repo's path contains a space, which
// import.meta.url percent-encodes — the naive comparison never matches.
if (process.argv[1] && import.meta.url === pathToFileURL(process.argv[1]).href) {
  const r = genPackBundle();
  console.log(`pack bundle     ✓  ${r.files} files (handoff/verdant/pack.bundle.json)`);
}
